import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { fetchProducts, createPaymentPreference } from "../services/api";
import logo from "../assets/logo.png";
import "./Store.css";

const CATEGORIES = [
  "Todas",
  "Cepillos",
  "Pastas dentales",
  "Hilo dental",
  "Blanqueadores",
  "Enjuague bucal",
  "Otros",
];

const categoryIcon = {
  Cepillos: "🪥",
  "Pastas dentales": "🧴",
  "Hilo dental": "🧵",
  Blanqueadores: "✨",
  "Enjuague bucal": "💧",
  Otros: "📦",
};

export default function Store() {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [activeCategory, setActiveCategory] = useState("Todas");
  const [cart, setCart] = useState([]);
  const [showCart, setShowCart] = useState(false);
  const [loading, setLoading] = useState(true);
  const [currentImage, setCurrentImage] = useState(0);

  const navigate = useNavigate();

  const slides = [
    {
      image:
        "https://gacetamedica.com/wp-content/uploads/2023/06/GettyImages-1409041204.jpg",
      title: "Tu salud importa",
      subtitle: "➡️ Jornadas de atención gratuita ⬅️",
    },
    {
      image:
        "https://cdn.firespring.com/images/80f7ee1f-f74d-4840-ad81-4eb596834a04.jpg",
      title: "Tu sonrisa es digna",
      subtitle: "➡️ Atención personalizada ⬅️",
    },
    {
      image:
        "https://sdk-dentalcollege.edu.in/sdk-cms/images/bannerimages/1524651961_large.jpg",
      title: "Tu derecho es nuestra accesibilidad",
      subtitle: "➡️ Jornadas odontológicas barriales gratuitas ⬅️",
    },
  ];

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentImage((prev) => (prev + 1) % slides.length);
    }, 3000);

    return () => clearInterval(interval);
  }, []);

  const isLoggedIn = Boolean(localStorage.getItem("token"));

  useEffect(() => {
    fetchProducts()
      .then((res) => {
        setProducts(res.data || []);
        setFiltered(res.data || []);
      })
      .finally(() => setLoading(false));
  }, []);

  const handleFilter = (cat) => {
    setActiveCategory(cat);
    if (cat === "Todas") setFiltered(products);
    else setFiltered(products.filter((p) => p.category === cat));
  };

  const handleAddToCart = (product) => {
    if (!isLoggedIn) return navigate("/login");

    setCart((prev) => {
      const existing = prev.find((i) => i.id === product.id);
      if (existing) {
        return prev.map((i) =>
          i.id === product.id ? { ...i, qty: i.qty + 1 } : i,
        );
      }
      return [...prev, { ...product, qty: 1 }];
    });
  };

  const handleRemoveFromCart = (id) => {
    setCart((prev) => prev.filter((i) => i.id !== id));
  };

  const handleCheckout = async () => {
    try {
      const res = await createPaymentPreference(cart);

      alert(
        `Compra realizada ✔\nTotal: $${res.data.total}\nID: ${res.data.orderId}`,
      );

      setCart([]);
      setShowCart(false);
    } catch {
      alert("Error al procesar la compra");
    }
  };

  const cartCount = cart.reduce((sum, i) => sum + i.qty, 0);
  const cartTotal = cart.reduce((sum, i) => sum + i.price * i.qty, 0);

  const isInCart = (id) => cart.some((i) => i.id === id);

  return (
    <div className="store-page">
      <div style={{ position: "relative" }}>
        <div className="store-carousel">
          <div
            className="store-carousel-slide"
            style={{
              backgroundImage: `url(${slides[currentImage].image})`,
            }}
          >
            <div className="store-carousel-overlay">
              <img src={logo} className="store-logo" alt="logo" />
              <h1 className="store-carousel-title">
                {slides[currentImage].title}
              </h1>
              <p className="store-carousel-subtitle">
                {slides[currentImage].subtitle}
              </p>
            </div>
          </div>
        </div>

        {cartCount > 0 && (
          <div className="store-cart-top">
            <button onClick={() => navigate("/checkout", { state: { cart } })}>
              🛒 {cartCount} | ${cartTotal.toFixed(2)}
            </button>
          </div>
        )}
      </div>

      <hr />

      <div className="store-container">
        <div className="store-filters">
          {CATEGORIES.map((cat) => (
            <button
              key={cat}
              className={activeCategory === cat ? "active" : ""}
              onClick={() => handleFilter(cat)}
            >
              {cat}
            </button>
          ))}
        </div>

        {loading ? (
          <p>Cargando productos...</p>
        ) : filtered.length === 0 ? (
          <div>No hay productos en esta categoría.</div>
        ) : (
          <div className="store-grid">
            {filtered.map((p) => {
              const outOfStock = p.stock === 0;
              const inCart = isInCart(p.id);

              return (
                <div key={p.id} className="store-card">
                  <div className="store-img">
                    {p.imageUrl ? (
                      <img src={p.imageUrl} alt={p.name} />
                    ) : (
                      categoryIcon[p.category] || "📦"
                    )}
                  </div>

                  <div className="store-body">
                    <span className="store-category">{p.category}</span>

                    <div>{p.name}</div>

                    <div>{p.description || "—"}</div>

                    <div className="store-row">
                      <div className="store-price">
                        ${Number(p.price).toFixed(2)}
                      </div>
                      <div
                        className={
                          outOfStock ? "store-stock out" : "store-stock ok"
                        }
                      >
                        {outOfStock ? "Sin stock" : `${p.stock} disponibles`}
                      </div>
                    </div>

                    <button
                      onClick={() => handleAddToCart(p)}
                      disabled={outOfStock}
                    >
                      {outOfStock
                        ? "No disponible"
                        : inCart
                          ? "En el carrito"
                          : "Agregar al carrito"}
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {cartCount > 0 && (
        <div className="store-cart-bar">
          <div>
            🛒 {cartCount} productos • ${cartTotal.toFixed(2)}
          </div>
          <button onClick={() => setShowCart(true)}>Ver carrito</button>
        </div>
      )}

      {showCart && (
        <div className="store-modal" onClick={() => setShowCart(false)}>
          <div className="store-modal-box" onClick={(e) => e.stopPropagation()}>
            <div>Tu carrito 🧾</div>

            {cart.length === 0 ? (
              <p>Tu carrito está vacío.</p>
            ) : (
              <>
                {cart.map((item) => (
                  <div key={item.id} className="store-modal-item">
                    <div>
                      <div>{item.name}</div>
                      <div>Cantidad: {item.qty}</div>
                    </div>

                    <div>
                      <div>${(item.price * item.qty).toFixed(2)}</div>
                      <button onClick={() => handleRemoveFromCart(item.id)}>
                        Quitar
                      </button>
                    </div>
                  </div>
                ))}

                <div className="store-modal-total">
                  <span>Total</span>
                  <span>${cartTotal.toFixed(2)}</span>
                </div>

                <div className="store-modal-actions">
                  <button onClick={() => setShowCart(false)}>
                    Seguir comprando
                  </button>

                  <button
                    onClick={() => navigate("/checkout", { state: { cart } })}
                  >
                    Finalizar compra
                  </button>
                </div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
}
